package com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.inbound.streams;

import com.sixgroup.refit.tradevalidator.data.file.adapter.config.AdapterProperties;
import com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.inbound.streams.mappers.FileAdapterMapper;
import com.sixgroup.refit.data.file.adapter.internal.FileKeyJoined;
import com.sixgroup.refit.data.file.adapter.internal.FileValueJoined;
import com.sixgroup.refit.data.filegovernance.topic.FileKey;
import com.sixgroup.refit.data.filegovernance.topic.FileValue;
import com.sixgroup.refit.observability.modules.log.kafka.infrastructure.streams.RftKafkaStreamsTracing;
import com.sixgroup.refit.tradevalidator.domain.FileId;
import com.sixgroup.refit.tradevalidator.topic.filevalidated.FileValidated;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.apache.kafka.streams.KeyValue;
import org.apache.kafka.streams.StreamsBuilder;
import org.apache.kafka.streams.kstream.KStream;
import org.apache.kafka.streams.kstream.Materialized;
import org.springframework.stereotype.Component;

import java.util.Objects;

import static com.sixgroup.refit.tradevalidator.data.file.adapter.shared.ApplicationConstants.CUSTOMER_GLOBAL_STORE;

@Slf4j
@Component
@RequiredArgsConstructor
public class MainStreamBuilder {

    private static final String ORIGIN_FTAP = "FTAP";

    private final AdapterProperties properties;
    private final FileAdapterMapper fileAdapterMapper;

    public KStream<FileKey, FileValue> build(StreamsBuilder builder) {

        // Input topic
        KStream<FileId, FileValidated> fileValidatedStream = builder.stream(properties.getFileValidatedTopic());

        // Global KTables
        builder.globalTable(properties.getCustomerTopic(), Materialized.as(CUSTOMER_GLOBAL_STORE));

        // Transform and map
        KStream<FileKeyJoined, FileValueJoined> transformedFileValidatorStream = fileValidatedStream
            .map((key, value) -> new KeyValue<>(getFileKeyJoined(key.getFileId()), getFileValueJoined(value)));

        // Adapt to data model and send to output topic
        KStream<FileKey, FileValue> adaptToData = transformedFileValidatorStream
            .map((k, v) -> KeyValue.pair(FileId.newBuilder().setFileId(k.getFileId()).build(), v.getFileValidated()))
            .filter((k, v) -> Objects.nonNull(v) && Objects.nonNull(v.getFileContext()))
            .map(fileAdapterMapper);

        adaptToData.to(properties.getDataFileTopic());

        return adaptToData;
    }

    private FileKeyJoined getFileKeyJoined(final String fileId) {
        return FileKeyJoined.newBuilder().setFileId(fileId).build();
    }

    private FileValueJoined getFileValueJoined(final FileValidated fileValidated) {
        return FileValueJoined.newBuilder()
            .setFileValidated(fileValidated)
            .setType(fileValidated.getFileContext().getType())
            .setOrigin(ORIGIN_FTAP)
            .build();
    }
}

package com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.inbound.streams.mappers;

import com.sixgroup.refit.common.spring.support.metrics.annotations.RftActionTimed;
import com.sixgroup.refit.tradevalidator.data.file.adapter.config.AdapterProperties;
import com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.outbound.CustomerKtableRepositoryImpl;
import com.sixgroup.refit.data.filegovernance.topic.FileKey;
import com.sixgroup.refit.data.filegovernance.topic.FileValue;
import com.sixgroup.refit.tradevalidator.domain.FileId;
import com.sixgroup.refit.tradevalidator.topic.filevalidated.FileValidated;
import lombok.RequiredArgsConstructor;
import org.apache.commons.lang3.StringUtils;
import org.apache.kafka.streams.KeyValue;
import org.apache.kafka.streams.kstream.KeyValueMapper;
import org.springframework.stereotype.Component;

import java.util.Objects;

@Component
@RequiredArgsConstructor
public class FileAdapterMapper implements KeyValueMapper<FileId, FileValidated, KeyValue<FileKey, FileValue>> {

    private final AdapterProperties properties;
    private final CustomerKtableRepositoryImpl customerRepository;

    @Override
    @RftActionTimed(value = "adapt_to_data")
    public KeyValue<FileKey, FileValue> apply(FileId fileId, FileValidated fileValidated) {
        return KeyValue.pair(FileKey.newBuilder().setFileId(fileId.getFileId()).build(),
            StreamMapper.fileValidatedAndReadyToFileValue(fileValidated, fileId, getSubmitgAgtAcnt(fileValidated), getSubmitgAgt(fileValidated), getSchema(fileValidated)));
    }

    public String getSchema(FileValidated value) {
        String schema = properties.getSchemaVersion().get(value.getFileContext().getType());
        return Objects.nonNull(schema) ? schema : "--";
    }

    @RftActionTimed(value = "get_submitgagt")
    public String getSubmitgAgt(FileValidated value) {
        return customerRepository.getCustomerLeiByAccount(getSubmitgAgtAcnt(value));
    }

    private String getSubmitgAgtAcnt(FileValidated value){
        // Defensive checks to prevent NullPointerExceptions
        if (value == null || value.getFileContext() == null) {
            // Log this situation or return a safe default, depending on business requirements.
            // Returning an empty string is often a safe default for missing identifiers.
            return "";
        }

        String fileName = value.getFileContext().getName();

        // Handle null or blank file name to prevent ArrayIndexOutOfBoundsException
        // from StringUtils.split("", "_") returning an empty array.
        if (StringUtils.isBlank(fileName)) {
            return "";
        }

        // StringUtils.split will return an array with at least one element if fileName is not blank.
        // E.g., "test" -> ["test"], "test_123" -> ["test", "123"], "_test" -> ["", "test"]
        String[] splitName = StringUtils.split(fileName, "_");

        // After the isBlank check, splitName is guaranteed to be non-null and have length >= 1.
        // Therefore, accessing splitName[0] is safe here.
        return splitName[0];
    }

}

package com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.inbound.streams.mappers;

import com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.inbound.streams.mappers.exception.MapperException;
import com.sixgroup.refit.data.filegovernance.topic.FileValue;
import com.sixgroup.refit.tradevalidator.domain.ErrorDetails;
import com.sixgroup.refit.tradevalidator.domain.FileId;
import com.sixgroup.refit.tradevalidator.topic.filevalidated.FileValidated;
import io.micrometer.common.util.StringUtils;
import lombok.extern.slf4j.Slf4j;
import org.springframework.util.CollectionUtils;

import java.util.ArrayList;
import java.util.List;
import java.util.Objects;
import java.util.stream.Collectors;

import static com.sixgroup.refit.observability.modules.log.error.codes.data.ErrorDataType.MAPPING_FILE_VALIDATED_TO_FILE_VALUE;

@Slf4j
public class StreamMapper {

    private static final String STATUS_ACPT = "ACPT";
    private StreamMapper() {
        throw new IllegalStateException("Utility class");
    }

    public static FileValue fileValidatedAndReadyToFileValue(FileValidated fileValidated, FileId fileId, String submitgAgtAcnt,
                                                             String submitgAgt, String schema) {
        try {

            FileValue.Builder fileValue = FileValue.newBuilder().setFileId(fileId.getFileId())
                .setChannel(fileValidated.getFileContext().getChannel())
                .setHeaderEnv(fileValidated.getFileContext().getHeader().getEnvironment())
                .setFileName(fileValidated.getFileContext().getName())
                .setHeaderIdFrom(fileValidated.getFileContext().getHeader().getSenderId())
                .setHeaderIdTo(fileValidated.getFileContext().getHeader().getRecipientId())
                .setHeaderMessageDate(fileValidated.getFileContext().getHeader().getMessageCreationDate())
                .setHeaderMessageDef(fileValidated.getFileContext().getHeader().getMessageId())
                .setReceivedTmstmp(fileValidated.getFileContext().getFileReceptionTimestamp())
                .setSubmitgAgt(submitgAgt)
                .setSubmitgAgtAcnt(submitgAgtAcnt)
                .setSchemaName(schema)
                .setSchemaType(fileValidated.getFileContext().getType());
            if(StringUtils.isEmpty(fileValidated.getFileContext().getStatus())){
                fileValue.setStatus(STATUS_ACPT);
            }else{
                fileValue.setStatus(fileValidated.getFileContext().getStatus());
            }
            completeErrors(fileValue,fileValidated);
            return fileValue.build();
        } catch (Exception e) {
            //MAPPING_FILE_VALIDATED_TO_FILE_VALUE
            log.error("Error mapping file value: {}", MAPPING_FILE_VALIDATED_TO_FILE_VALUE, e);
            throw new MapperException("Error mapping file validated to  file value", e);
        }
    }

    private static void completeErrors(FileValue.Builder fileValue, FileValidated fileValidated){
        List<ErrorDetails> errorDetailsList = fileValidated.getFileContext().getErrorDetails();
        if(!CollectionUtils.isEmpty(errorDetailsList)){
            fileValue.setErrorCode(errorDetailsList.stream().map(ErrorDetails::getErrorCode).collect(Collectors.toList()));
            fileValue.setErrorDesc(errorDetailsList.stream().map(ErrorDetails::getErrorDesc).collect(Collectors.toList()));
            fileValue.setErrorId(errorDetailsList.stream()
                .map(ErrorDetails::getErrorId)
                .filter(Objects::nonNull) // Added null check for errorId string
                .map(Integer::parseInt).collect(Collectors.toList()));
            fileValue.setErrorPath(getErrorPathList(errorDetailsList));
        }
    }

    private static List<String> getErrorPathList(List<ErrorDetails> list) {
        if (list == null) {
            return new ArrayList<>();
        }
        return list.stream()
            .filter(Objects::nonNull)
            .map(ErrorDetails::getErrorPath) // Corrected from getErrorDesc to getErrorPath
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }



}

