package com.sixgroup.refit.tradevalidator.data.file.adapter.infrastructure.outbound;

import com.sixgroup.refit.tradevalidator.data.file.adapter.interfaces.CustomerRepository;
import com.sixgroup.refit.tradevalidator.domain.CustomerId;
import com.sixgroup.refit.tradevalidator.topic.customer.CustomerData;
import lombok.RequiredArgsConstructor;
import org.apache.kafka.streams.StoreQueryParameters;
import org.apache.kafka.streams.state.QueryableStoreTypes;
import org.apache.kafka.streams.state.ReadOnlyKeyValueStore;
import org.springframework.kafka.config.StreamsBuilderFactoryBean;
import org.springframework.stereotype.Repository;

import java.util.Objects;
import org.springframework.util.StringUtils; // Import for StringUtils

import static com.sixgroup.refit.tradevalidator.data.file.adapter.shared.ApplicationConstants.CUSTOMER_GLOBAL_STORE;
import static com.sixgroup.refit.tradevalidator.data.file.adapter.shared.ApplicationConstants.CUSTOMER_NOT_FOUND;

@RequiredArgsConstructor
@Repository
public class CustomerKtableRepositoryImpl implements CustomerRepository {

    private final StreamsBuilderFactoryBean streamsBuilderFactoryBean;

    @Override
    public String getCustomerLeiByAccount(final String account) {
        // Input validation: Ensure the account is not null or empty
        if (!StringUtils.hasText(account)) {
            // Log the issue and return the "not found" constant or throw a specific exception
            // For simplicity, returning CUSTOMER_NOT_FOUND as per existing pattern for non-existent data.
            // A more robust solution might throw an IllegalArgumentException.
            return CUSTOMER_NOT_FOUND;
        }

        final ReadOnlyKeyValueStore<CustomerId, CustomerData> store =
                Objects.requireNonNull(streamsBuilderFactoryBean.getKafkaStreams(), "Kafka Streams instance must not be null")
                        .store(StoreQueryParameters
                                .fromNameAndType(CUSTOMER_GLOBAL_STORE, QueryableStoreTypes.keyValueStore()));

        final CustomerData customer = store.get(CustomerId.newBuilder().setAccountCode(account).build());

        return Objects.nonNull(customer) && Objects.nonNull(customer.getCustomer()) ? customer.getCustomer().getAccountLEI() : CUSTOMER_NOT_FOUND;
    }
}

